mapper.select:
select
(select count(*) from gz_shipment_entry se inner join gz_shipment gs on gs.id = se.paren_id and ifnull(gs.del_flag, 0) != 1 and gs.tenant_id = #{scopedTenantId}
left join fd_material m on se.material_id = m.id
where ifnull(se.del_flag, 0) != 1
)
+
(select count(*) from gz_refund_stock_entry rse inner join gz_refund_stock rs on rs.id = rse.paren_id and ifnull(rs.del_flag, 0) != 1 and rs.tenant_id = #{scopedTenantId}
left join fd_material m on rse.material_id = m.id
where ifnull(rse.del_flag, 0) != 1
)

select * from ( ( select se.id as entryId, 'shipment' as billKind, '备货出库' as billTypeName, gs.shipment_no as orderNo, gs.shipment_status as orderStatus, gs.shipment_date as orderDate, gs.audit_date as auditDate, gs.create_by as createBy, gs.update_by as updateBy, gs.audit_by as auditBy, se.material_id as materialId, m.code as materialCode, m.name as materialName, m.speci as materialSpeci, m.model as materialModel, u.unit_name as unitName, f.factory_name as factoryName, m.register_no as registerNo, m.period_date as periodDate, m.udi_no as udiNo, se.price as price, se.qty as qty, se.amt as amt, se.batch_no as batchNo, se.batch_number as batchNumber, se.begin_time as beginTime, se.end_time as endTime, se.in_hospital_code as inHospitalCode, gs.warehouse_id as warehouseId, w.name as warehouseName, gs.department_id as departmentId, d.name as departmentName, coalesce(se.supplier_id, m.supplier_id) as supplierId, gs.create_time as sortTime from gz_shipment_entry se inner join gz_shipment gs on gs.id = se.paren_id and ifnull(gs.del_flag, 0) != 1 and gs.tenant_id = #{scopedTenantId} left join fd_warehouse w on gs.warehouse_id = w.id left join fd_department d on gs.department_id = d.id left join fd_material m on se.material_id = m.id left join fd_unit u on m.unit_id = u.unit_id left join fd_factory f on m.factory_id = f.factory_id where ifnull(se.del_flag, 0) != 1
and 1 = 0
order by gs.create_time desc, se.id desc
limit #{branchFetchLimit}
)
union all
( select rse.id as entryId, 'refundStock' as billKind, '备货退库' as billTypeName, rs.refund_no as orderNo, rs.refund_status as orderStatus, rs.refund_date as orderDate, rs.audit_date as auditDate, rs.create_by as createBy, rs.update_by as updateBy, rs.audit_by as auditBy, rse.material_id as materialId, m.code as materialCode, m.name as materialName, m.speci as materialSpeci, m.model as materialModel, u.unit_name as unitName, f.factory_name as factoryName, m.register_no as registerNo, m.period_date as periodDate, m.udi_no as udiNo, rse.price as price, rse.qty as qty, rse.amt as amt, rse.batch_no as batchNo, rse.batch_number as batchNumber, rse.begin_time as beginTime, rse.end_time as endTime, rse.in_hospital_code as inHospitalCode, rs.warehouse_id as warehouseId, w.name as warehouseName, rs.department_id as departmentId, d.name as departmentName, m.supplier_id as supplierId, rs.create_time as sortTime from gz_refund_stock_entry rse inner join gz_refund_stock rs on rs.id = rse.paren_id and ifnull(rs.del_flag, 0) != 1 and rs.tenant_id = #{scopedTenantId} left join fd_warehouse w on rs.warehouse_id = w.id left join fd_department d on rs.department_id = d.id left join fd_material m on rse.material_id = m.id left join fd_unit u on m.unit_id = u.unit_id left join fd_factory f on m.factory_id = f.factory_id where ifnull(rse.del_flag, 0) != 1
and 1 = 0
order by rs.create_time desc, rse.id desc
limit #{branchFetchLimit}
) ) t order by t.sortTime desc, t.entryId desc

select se.id as shipmentEntryId, gs.id as shipmentId, gs.shipment_no as shipmentNo, gs.department_id as departmentId, d.name as departmentName, se.batch_no as batchNo, se.material_id as materialId, gs.warehouse_id as warehouseId, se.in_hospital_code as wrongInHospitalCode, di.in_hospital_code as correctInHospitalCode, gdi.id as depInventoryId from gz_depot_inventory di inner join gz_shipment_entry se on se.batch_no = di.batch_no and se.material_id = di.material_id and se.del_flag != 1 inner join gz_shipment gs on gs.id = se.paren_id and gs.del_flag != 1 and gs.shipment_status = 2 left join fd_department d on d.id = gs.department_id left join gz_dep_inventory gdi on gdi.department_id = gs.department_id and gdi.in_hospital_code = se.in_hospital_code and gdi.del_flag != 1 and gdi.tenant_id = #{scopedTenantId} where di.del_flag != 1 and di.tenant_id = #{scopedTenantId} and gs.tenant_id = #{scopedTenantId} and di.in_hospital_code = #{inHospitalCode} and (se.in_hospital_code is null or trim(se.in_hospital_code) = '' or se.in_hospital_code != di.in_hospital_code)
and gs.shipment_no = #{shipmentNo}
order by coalesce(gs.audit_date, gs.create_time) desc, se.id desc limit 1

mapper.update:

update gz_dep_flow
set in_hospital_code = #{correctCode}
where tenant_id = #{scopedTenantId}
  and in_hospital_code = #{wrongCode}
  and ifnull(del_flag, 0) = 0


update gz_wh_flow
set in_hospital_code = #{correctCode}
where tenant_id = #{scopedTenantId}
  and in_hospital_code = #{wrongCode}
  and bill_no = #{shipmentNo}
  and lx = 'CK'
  and ifnull(del_flag, 0) = 0
